function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

function asList<T>(data: unknown): T[] {
  if (Array.isArray(data)) return data as T[];
  const d = data as { items?: T[] };
  if (Array.isArray(d?.items)) return d.items;
  return [];
}

async function getList<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T[]> {
  const qs = params ? `?${buildQs(params)}` : '';
  const res = await apiClient.get<BffResponse<T[] | { items: T[] }>>(`${path}${qs}`);
  return asList<T>(unwrap(res));
}

